```cpp
// ((X & 1) +nuw/nsw (Y & 1)) >>u 1 --> (X & 1) & Y
// The sum of two low bits is 0, 1, or 2. Shifting right by 1 gives 1
// only when both bits are set, which equals (X & 1) & (Y & 1) = X & Y & 1.
// The output uses the LHS and result and ANDs with RHS's source to maintain
// consistent IR structure.
if (C->eq(APInt(BitWidth, 1))) {
  Value *LHSAndSrc, *RHSAndSrc;
  const APInt *LHSAndMask, *RHSAndMask;
  BinaryOperator *AddOp;
  // Use non-commutative m_Add to match exact operand order
  if (match(Op0, m_OneUse(m_Add(m_And(m_Value(LHSAndSrc), m_APInt(LHSAndMask)),
                                  m_And(m_Value(RHSAndSrc), m_APInt(RHSAndMask)))))) {
    AddOp = cast<BinaryOperator>(Op0);
    if (AddOp->hasNoUnsignedWrap() && AddOp->hasNoSignedWrap() &&
        *LHSAndMask == 1 && *RHSAndMask == 1) {
      // Produce: (RHSAndSrc & 1) & LHSAndSrc
      // This matches the expected pattern: first and with RHS source, then and with LHS source
